import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { PageView } from '../components/PageView';
import { AnalyticsService } from '../services/AnalyticsService';

// Assume AnalyticsService is a singleton for the app lifecycle
const appAnalyticsService = new AnalyticsService();

export function AppRouter() {
  return (
    <Router>
      <Routes>
        <Route
          path="/page/:pageId"
          element={
            // CRUCIAL FIX: Use key={pageId} to force component remount on pageId change.
            // This ensures that when the pageId parameter changes, React considers it a
            // *new* instance of PageView, unmounting the old one and mounting a new one.
            // This reliably triggers the useEffect cleanup in useScrollAnalytics.
            <PageView
              key={window.location.pathname} // Using pathname ensures a unique key per URL
              pageId={window.location.pathname} // Example: derive pageId from URL
              analyticsService={appAnalyticsService}
            />
          }
        />
        {/* ... other routes ... */}
      </Routes>
